// Command reglint provides the CLI entrypoint.
package main

import (
	"io"
	"os"

	"github.com/iyaki/reglint/internal/cli"
)

var (
	args                   = os.Args
	outputWriter io.Writer = os.Stdout
	exitFunc               = os.Exit
)

func main() {
	code := run(args[1:], outputWriter)
	exitFunc(code)
}
